import React, { useState, useEffect } from 'react';

const Timer = ({ initialValue = 60 }) => {
    const [time, setTime] = useState(initialValue); // Default 60 seconds
    const [isRunning, setIsRunning] = useState(false);
    const [initialTime, setInitialTime] = useState(initialValue);
    const radius = 120;
    const circumference = 2 * Math.PI * radius;
    const strokeDashoffset = circumference * (1 - time / initialTime);

    // prima..
    /* useEffect(() => {
        let intervalId;
        if (isRunning && time > 0) {
            intervalId = setInterval(() => {
                setTime((prevTime) => {
                    if (prevTime <= 1) {
                        playAlarm();
                        setIsRunning(false);
                        return 0;
                    }
                    return prevTime - 1;
                });
            }, 1000);
        }
        return () => clearInterval(intervalId);
    }, [isRunning]); */

    // Testing..
    const [startTime, setStartTime] = useState(null);
    useEffect(() => {
        let intervalId;
        if (isRunning) {
            const start = Date.now() - (initialTime - time) * 1000;
            setStartTime(start);

            intervalId = setInterval(() => {
                const elapsed = Math.floor((Date.now() - start) / 1000);
                const newTime = Math.max(0, initialTime - elapsed);
                setTime(newTime);

                if (newTime === 0) {
                    playAlarm();
                    setIsRunning(false);
                    clearInterval(intervalId);
                }
            }, 500); // meglio controllare più frequentemente
        }
        return () => clearInterval(intervalId);
    }, [isRunning, initialTime]);

    const toggleTimer = () => {
        setIsRunning(!isRunning);
    };

    const resetTimer = () => {
        setIsRunning(false);
        setTime(initialTime);
    };

    const adjustTime = (amount) => {
        if (!isRunning) {
            const newTime = Math.max(0, initialTime + amount);
            setInitialTime(newTime);
            setTime(newTime);
        }
    };

    const playAlarm = () => {
        // const audio = new Audio('data:audio/wav;base64,');
        const audio = new Audio("/app/sounds/timer.wav");
        audio.play();
    };

    const formatTime = (seconds) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    return (
        <div className="timer-container">
            <div className="timer-display">
                <svg className="timer-svg">
                    <circle
                        cx="50%"
                        cy="50%"
                        r={radius}
                        fill="none"
                        className="timer-circle--bg"
                        strokeWidth="7"
                    />
                    <circle
                        cx="50%"
                        cy="50%"
                        r={radius}
                        fill="none"
                        className="timer-circle--progress"
                        strokeWidth="7"
                        strokeDasharray={circumference}
                        strokeDashoffset={strokeDashoffset}
                    />
                </svg>
                <h2 className="display-4 timer-text">
                    {formatTime(time)}
                </h2>

                <div className="timer-controls--time">
                    <button
                        onClick={() => adjustTime(-5)}
                        disabled={isRunning || initialTime <= 5}
                        className="btn btn-outline-dark"
                    >
                        <i className="fas fa-minus"></i>
                    </button>
                    <button
                        onClick={() => adjustTime(5)}
                        disabled={isRunning}
                        className="btn btn-outline-dark"
                    >
                        <i className="fas fa-plus"></i>
                    </button>
                </div>
            </div>

            <div className="timer-controls">
                <button
                    className={`btn ${isRunning ? 'btn-outline-primary' : 'btn-primary'}`}
                    onClick={toggleTimer}
                >
                    <i className={`fas ${isRunning ? 'fa-pause' : 'fa-play'} me-1`}></i>
                    {isRunning ? 'Pause' : 'Start'}
                </button>
                <button
                    className="btn btn-outline-secondary"
                    onClick={resetTimer}
                >
                    <i className="fas fa-redo me-1"></i>
                    Reset
                </button>
            </div>
        </div>
    );
};

export default Timer;