export const capitalize = (string = '') => string.charAt(0).toUpperCase() + string.slice(1);

export const renderClass = (initClass, addClass = null) => `${initClass}${addClass ? ` ${addClass}` : ''}`;

export const getFullImagePath = (imagePath) => {
    if (!imagePath) return;
    return `${process.env.REACT_APP_BASE_URL}/${imagePath}`;
}

export const setMessageErrorObject = (message) => {
    return { response: { data: { message } } }
}

/**
 * Genera le iniziali di un utente basandosi su nome, cognome o username
 * Supporta sia la struttura con anagrafica (user.anagrafica.nome) che quella flat (user.nome)
 * @param {Object} userData - Oggetto contenente nome, cognome e/o username
 * @param {Object} userData.anagrafica - Oggetto anagrafica (può essere null)
 * @param {string} userData.anagrafica?.nome - Nome dell'utente nell'anagrafica
 * @param {string} userData.anagrafica?.cognome - Cognome dell'utente nell'anagrafica
 * @param {string} userData.nome - Nome dell'utente (se presente direttamente)
 * @param {string} userData.cognome - Cognome dell'utente (se presente direttamente)
 * @param {string} userData.username - Username dell'utente
 * @returns {string} Le iniziali dell'utente (es. "MR" per Mario Rossi) o "U" come fallback
 */
export const getUserInitials = (userData = {}) => {
    // Prova prima a prendere nome e cognome direttamente dall'oggetto
    let nome = userData?.nome || '';
    let cognome = userData?.cognome || '';
    
    // Se non presenti, prova a prenderli dall'anagrafica
    if (!nome && !cognome && userData?.anagrafica) {
        nome = userData.anagrafica?.nome || '';
        cognome = userData.anagrafica?.cognome || '';
    }
    
    if (nome && cognome) {
        return `${nome[0]}${cognome[0]}`.toUpperCase();
    }
    
    return (userData?.username || 'U')[0].toUpperCase();
}

/**
 * Ottiene il nome completo dell'utente (nome e cognome se presenti, altrimenti username)
 * Supporta sia la struttura con anagrafica (user.anagrafica.nome) che quella flat (user.nome)
 * @param {Object} userData - Oggetto contenente nome, cognome e/o username
 * @param {Object} userData.anagrafica - Oggetto anagrafica (può essere null)
 * @param {string} userData.anagrafica?.nome - Nome dell'utente nell'anagrafica
 * @param {string} userData.anagrafica?.cognome - Cognome dell'utente nell'anagrafica
 * @param {string} userData.nome - Nome dell'utente (se presente direttamente)
 * @param {string} userData.cognome - Cognome dell'utente (se presente direttamente)
 * @param {string} userData.username - Username dell'utente
 * @param {string} fallback - Testo di fallback se non è presente né nome/cognome né username (default: 'Utente')
 * @returns {string} Il nome completo dell'utente (es. "Mario Rossi") o lo username come fallback
 */
export const getUserName = (userData = {}, fallback = 'Utente') => {
    // Prova prima a prendere nome e cognome direttamente dall'oggetto
    let nome = userData?.nome || '';
    let cognome = userData?.cognome || '';
    
    // Se non presenti, prova a prenderli dall'anagrafica
    if (!nome && !cognome && userData?.anagrafica) {
        nome = userData.anagrafica?.nome || '';
        cognome = userData.anagrafica?.cognome || '';
    }
    
    if (nome && cognome) {
        return `${nome} ${cognome}`;
    }
    
    return userData?.username || fallback;
}