export const Form = ({ className = null, children }) => {
    const onSubmit = (e) => {
        e.preventDefault();
    }

    return (
        <form onSubmit={onSubmit} className={className} noValidate>
            {children}
        </form>
    );
}

export const Input = ({ name, title, type = 'text', placeholder = "Inserisci valore", value = null, onInput, onFocus = null, autoComplete = 'off', min = null, max = null, error = null }) => {
    return (
        <>
            <label htmlFor={name}>{title}</label>
            <input
                type={type}
                name={name}
                placeholder={placeholder}
                value={value != null ? value : ''}
                min={min}
                max={max}
                onChange={onInput}
                onFocus={onFocus}
                autoComplete={autoComplete}
                className={`form-control my-form-control${error ? " is-invalid" : ''}`} />
            {error && <InputError error={error} />}
        </>
    );
}

export const Textarea = ({ name, title, type = 'text', placeholder = null, value = null, onInput, autoComplete = 'off', errors = null }) => {
    // TODO per gestire dinamicamente il numero di righe della textarea man mano che aumenta il numero di parole
    /* const getNumberOfRows = () => {
        const words = value.split(' ').length;
        return (!!value && words > 100) ? (words / 25) - 1 : 3
    } */

    return (
        <>
            <label htmlFor={name}>{title}</label>
            <textarea rows={'3'} type={type} name={name} placeholder={placeholder} value={value != null ? value : ''} onChange={onInput} autoComplete={autoComplete} />
            {errors && <InputError error={errors[name]} />}
        </>
    );
}

export const Select = ({ name, title, options = [], value, onInput, error = null }) => {
    return (
        <>
            <label htmlFor={name}>{title}</label>
            <select 
                name={name} 
                value={!!value ? value : 'default'} 
                onChange={onInput}
                className={`form-control my-form-control${error ? " is-invalid" : ''}`}
            >
                <option value='default' disabled>Seleziona un'opzione</option>
                {
                    options.map((e, i) => (
                        <option value={e.value} key={i}>{e.name}</option>
                    ))
                }
            </select>
            {error && <InputError error={error} />}
        </>
    );
}

export const InputError = ({ error = null }) => {
    if (!error) return <></>

    return (
        <span role="alert" className="invalid-feedback"><strong>{error}</strong></span>
    )

}