import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import SchedaCreate from './pages/SchedaCreate';
import Scheda from './pages/Scheda';
import { Login } from './pages/auth/Login';
import ProtectedRoute from './components/ProtectedRoute';
import Allenamento from './pages/Allenamento';
import ErrorPage from './pages/ErrorPage';
import WorkoutList from './pages/WorkoutList';
import Register from './pages/auth/Register';
import DemoTimer from './pages/DemoTimer';
import Profilo from './pages/Profilo';

const App = () => {
  return (
    <Router basename="/app">
      <Routes>
        {/* Redirect dalla root alla home desiderata */}
        <Route path="/" element={<Navigate to="/workouts/last" replace />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        {/* Rotta di test per lo sviluppo del timer */}
        <Route path="/demo/timer" element={<DemoTimer />} />

        {/* Rotte dove è richiesta l'autenticazione */}
        <Route element={<ProtectedRoute />}>
          <Route path="/workouts" element={<WorkoutList />} />
          <Route path="/workouts/:id" element={<Scheda />} />
          <Route path="/workouts/last" element={<Scheda />} />
          <Route path="workouts/:id/day/:day" element={<Allenamento />} />
          <Route path="workouts/last/day/:day" element={<Allenamento />} />
          <Route path="/scheda/create" element={<SchedaCreate />} />
          <Route path="/profile" element={<Profilo />} />
        </Route>

        <Route path="/error" element={<ErrorPage />} />
        <Route path="*" element={<ErrorPage />} />
      </Routes>
    </Router>
  );
}

export default App;