import React from 'react'
import { Link, useLocation } from 'react-router-dom'
import { useSelector } from 'react-redux'
import { getUserInitials } from '../functions'

const Navbar = ({ onToggleSidebar }) => {
    const { user } = useSelector(state => state.user);
    const location = useLocation();

    const isActive = (path) => {
        if (path === '/workouts/last' || path === '/workouts') {
            return location.pathname.startsWith('/workouts');
        }
        return location.pathname === path;
    };

    return (
        <nav className="app-navbar">
            <div className="navbar-container">
                <div className="navbar-links">
                    <Link className={`navbar-link ${isActive('/workouts/last') ? 'active' : ''}`} to="/workouts/last"><i className="fa-solid fa-dumbbell"></i><span>Scheda</span></Link>
                    <a className="navbar-link" href="#"><i className="fa-solid fa-sliders"></i><span>Progressi</span></a>
                </div>

                <button
                    className="navbar-user-avatar"
                    onClick={onToggleSidebar}
                    aria-label="Apri menu"
                >
                    {user?.avatar_url ? (
                        <img
                            src={user.avatar_url}
                            alt="Avatar"
                            className="navbar-user-avatar-img"
                        />
                    ) : (
                        <div className="navbar-user-avatar-placeholder">
                            {getUserInitials(user)}
                        </div>
                    )}
                </button>
            </div>
        </nav>
    )
}

export default Navbar
